// src/routes/moneyworks/base/moneyworks.route.ts
function moneyworksRoute(model, objectSchema, service, detail) {
  const query = t.Object({
    limit: t.Optional(t.Numeric()),
    offset: t.Optional(t.Numeric()),
    sort: t.Optional(t.String()),
    order: t.Optional(t.String()),
    search: t.Optional(accountObject),
    format: t.Optional(t.String())
  });
  return new Elysia({ prefix: "/api" }).model(model, objectSchema).get(`/${model.toLowerCase()}s`, async (params) => {
    const {
      limit = 10,
      offset = 0,
      sort,
      order,
      search,
      format
    } = params.query;
    const fields = format ? format.split(",") : undefined;
    try {
      return await service.getData({
        limit: Number(limit),
        offset: Number(offset),
        sort: sort !== undefined ? String(sort) : undefined,
        order,
        search,
        fields
      });
    } catch (error) {
      console.error(`Error in GET /${model.toLowerCase()}s:`, error);
      throw error;
    }
  }, {
    query,
    detail,
    response: {
      200: t.Object({
        data: t.Array(objectSchema),
        pagination: t.Object({
          total: t.Integer(),
          limit: t.Integer(),
          offset: t.Integer(),
          next: t.Integer(),
          prev: t.Integer()
        })
      })
    }
  });
}

