class ReportService {
  config;
  api;
  constructor(config4) {
    this.config = config4;
    this.api = new MoneyWorksApiService(config4);
  }
  createAuthHeaders() {
    const documentCredentials = `${this.config.username}:Document:${this.config.password}`;
    const documentAuth = `Basic ${Buffer.from(documentCredentials).toString("base64")}`;
    if (this.config.folderAuth) {
      const { folderName, password } = this.config.folderAuth;
      const folderCredentials = `${folderName}:Datacentre:${password}`;
      const folderAuth = `Basic ${Buffer.from(folderCredentials).toString("base64")}`;
      return {
        Authorization: `${documentAuth}, ${folderAuth}`
      };
    }
    return {
      Authorization: documentAuth
    };
  }
  getBaseUrl() {
    return `http://${this.config.host}:${this.config.port}/REST/${encodeURIComponent(this.config.dataFile)}`;
  }
  async generateReport(reportName) {
    try {
      const url2 = `${this.getBaseUrl()}/doreport/report=${encodeURIComponent(reportName)}&format=html&leading=8&font=Verdana&size=10`;
      const headers = this.createAuthHeaders();
      const response = await axios_default.get(url2, {
        headers,
        responseType: "text"
      });
      return response.data;
    } catch (error) {
      console.error(`Error generating report "${reportName}":`, error);
      if (axios_default.isAxiosError(error)) {
        if (error.response) {
          throw new Error(`MoneyWorks Report Error: ${error.response.status} - ${JSON.stringify(error.response.data)}`);
        }
        if (error.request) {
          throw new Error(`MoneyWorks Report Error: No response received - ${error.message}`);
        }
      }
      throw new Error(`MoneyWorks Report Error: ${error.message}`);
    }
  }
}

